// Merge dormant + post-demo, deduplicate by email, attach type
const dormant  = $('Supabase — Dormant Leads (UC1)').all().map(i => ({ ...i.json, detection_type: 'dormant' }));
const postdemo = $('Supabase — Post-Demo No Follow-Up (UC2)').all().map(i => ({ ...i.json, detection_type: 'post_demo' }));
const seen = new Set();
const merged = [...dormant, ...postdemo].filter(lead => {
  if (!lead.email || seen.has(lead.email)) return false;
  seen.add(lead.email);
  return true;
});
console.log(`[01] Detected ${merged.length} leads to process (${dormant.length} dormant, ${postdemo.length} post-demo)`);
if (merged.length === 0) return [{ json: { skipped: true, reason: 'No leads to process' } }];
return merged.map(l => ({ json: l }));

// Merge score result back into lead
const lead  = $('Merge & Deduplicate Leads').first().json;
const score = $input.first().json;
if (score.error) {
  console.warn('Score API failed — using raw lead score:', lead.score);
  return [{ json: { ...lead, score: lead.score || 0, routing: lead.routing || 'cold', score_breakdown: {} } }];
}
return [{ json: { ...lead, score: score.score, routing: score.routing, score_breakdown: score.breakdown } }];

const lead = $('Merge Score Result').first().json;
const ragRows = $('Supabase — Fetch RAG Patterns').all().map(i => i.json);
const ragExamples = ragRows.map((r, i) => {
  const m = r.metadata || {};
  return `Example ${i+1}:
Subject: ${m.subject || 'N/A'}
Body: ${m.body || 'N/A'}
Outcome: ${m.outcome_score || '?'}% success rate`;
}).join('

') || 'No past examples yet — use best judgment.';
const prompt = `You are a senior B2B sales strategist. Write ONE cold re-engagement email for a lead who went silent.

LEAD CONTEXT
Name: ${lead.name}
Role: ${lead.role || 'unknown'}
Company: ${lead.company}
Industry: ${lead.industry || 'unknown'}
Company size: ${lead.company_size || 'unknown'} employees
Why we're reaching out: ${lead.detection_type === 'dormant' ? 'Never followed up after initial contact' : 'No activity since demo'}
Notes: ${lead.notes || 'none'}

SUCCESSFUL EMAIL PATTERNS (for reference — do not copy verbatim)
${ragExamples}

RULES
- Max 80 words in body
- Subject: max 8 words, no emoji, no exclamation
- No filler openers (no 'I hope this finds you well')
- No spam words (synergy, game-changer, leverage)
- End with ONE low-pressure question CTA
- Tone: direct, warm, peer-to-peer

OUTPUT FORMAT (strictly):
Subject: [subject line]

[email body]`;
return [{ json: { ...lead, _email_prompt: prompt } }];

